import datetime
from flask import Flask
from flask_jwt_extended import (
    JWTManager, jwt_required, create_access_token,
    get_jwt_identity)


app = Flask(__name__)
app.config['JWT_SECRET_KEY'] = 'super-secret'  # Change this!
jwt = JWTManager(app)


@app.route('/login')
def login():
    return create_access_token('user123', expires_delta=datetime.timedelta(days=7))


@app.route('/protected')
@jwt_required()
def protected():
    user_id = get_jwt_identity()
    return 'Logged in as {}'.format(user_id)


if __name__ == '__main__':
    app.run(debug=True, port=5001)